const body = $input.first().json.body || $input.first().json;
const entry = (body.entry || [])[0] || {};
const change = (entry.changes || [])[0] || {};
const value = change.value || {};
const messages = value.messages || [];

if (!messages.length) {
  return [{ json: { skip: true } }];
}

const msg = messages[0];
const from = msg.from;
const msgId = msg.id;
const timestamp = msg.timestamp;
const type = msg.type;

let text = '';
if (type === 'text') {
  text = msg.text?.body || '';
} else if (type === 'button') {
  text = msg.button?.text || '';
} else if (type === 'image') {
  text = msg.image?.caption || '';
} else if (type === 'document') {
  text = msg.document?.caption || '';
}

return [{ json: { from, msgId, timestamp, type, text, skip: false } }];

// ============================================================
// RIFAH Connect — Flow 2B State Machine (Premium Lead)
// ============================================================
const msgNode = $('Extract Message').first().json;
const sessionRaw = $('Get Session').first().json;
const memberRaw = $('Get Member').first().json;

const phone = msgNode.from;
const msgType = msgNode.type || 'text';
const rawText = msgNode.text || '';
const msgText = rawText.trim().toUpperCase();
const rawTextOriginal = rawText.trim();

// Parse session
const sessionDocs = sessionRaw?.data || [];
const sessionDoc = sessionDocs.length > 0 ? sessionDocs[0] : {};
let currentStep = sessionDoc.current_step || 'IDLE';
let sessionData = {};
try { sessionData = JSON.parse(sessionDoc.session_data || '{}'); } catch(e) {}
const sessionName = sessionDoc.name || null;

// Parse member
const memberDocs = memberRaw?.data || [];
const memberExists = memberDocs.length > 0;
const member = memberExists ? memberDocs[0] : null;

let responseMsg = '';
let nextStep = currentStep;
let action = 'none';
let actionData = {};

// ─── STEPS OWNED BY FLOW 2B ───────────────────────────────────
const leadSteps = ['LEAD_TYPE','LEAD_DESC','LEAD_LOC','LEAD_URGENCY','LEAD_BUDGET'];
const aiSteps = ['AI_Q1','AI_Q2','AI_Q3','AI_Q4','AI_Q5','AI_Q6'];
const premiumSteps = ['LEAD_CREATE','VENDOR_SELECTION','VENDOR_CONFIRM'];
const vendorSteps = ['VENDOR_INTRO','VENDOR_Q1','VENDOR_Q2','VENDOR_Q3','VENDOR_Q4','VENDOR_Q5','VENDOR_Q6','VENDOR_SCORE','VENDOR_SUBMIT'];
const flow2bSteps = [...leadSteps, ...aiSteps, ...premiumSteps, ...vendorSteps];

// Admin command detection (from admin WhatsApp number)
const adminPhone = sessionData._admin_phone || '';
const connectMatch = rawTextOriginal.match(/^CONNECT\s+(\S+)\s+(\S+)/i);
const declineMatch = rawTextOriginal.match(/^DECLINE\s+(\S+)\s+(\S+)/i);
if (connectMatch || declineMatch) {
  const m = connectMatch || declineMatch;
  action = 'admin_approval';
  actionData = {
    command: connectMatch ? 'CONNECT' : 'DECLINE',
    lead_id: m[1],
    vendor_id: m[2],
    admin_phone: phone
  };
  return [{ json: { phone, responseMsg: '', nextStep: currentStep, action, actionData: JSON.stringify(actionData), sessionData: JSON.stringify(sessionData), sessionName, currentStep, shouldSendMsg: false, skip: false } }];
}

if (!flow2bSteps.includes(currentStep)) {
  return [{ json: { skip: true, phone, currentStep } }];
}

// ─── PREMIUM GATE ─────────────────────────────────────────────
if (!member || member.membership_tier !== 'PREMIUM' || member.status !== 'Active Premium') {
  if (msgText === 'UPGRADE') {
    responseMsg = '💳 *Upgrade to PREMIUM (₹3,000/year)*\n\nBenefits:\n• ⚡ Instant smart matching from 1 lakh+ businesses\n• 📊 Top 10 vendors shown in 10 seconds\n• 📨 Direct personalized introductions\n• ⏱️ 2-hour admin response SLA\n• ⭐ PREMIUM REQUEST badge on group posts\n\nContact RIFAH admin to upgrade:\n[ADMIN_CONTACT]\n\nType MENU to return to main menu.';
  } else {
    responseMsg = '⭐ *PREMIUM Feature*\n\nThis feature is exclusive to PREMIUM members.\n\nUpgrade to PREMIUM (₹3,000/year) to get:\n• Instant smart matching\n• Top 10 vendors in 10 seconds\n• Direct vendor introductions\n• 2-hour SLA\n\nReply *UPGRADE* to learn more, or *MENU* to go back.';
  }
  return [{ json: { phone, responseMsg, nextStep: 'MENU', action: 'none', actionData: '{}', sessionData: JSON.stringify({ current_step: 'MENU' }), sessionName, currentStep, shouldSendMsg: true, skip: false } }];
}

// ─── STEP MACHINE ─────────────────────────────────────────────
switch (currentStep) {

  case 'LEAD_TYPE': {
    const typeMap = { '1':'BUY', '2':'SELL', '3':'SERVICE NEED', '4':'SERVICE OFFER',
                      'BUY':'BUY', 'SELL':'SELL', 'SERVICE NEED':'SERVICE NEED', 'SERVICE OFFER':'SERVICE OFFER' };
    const type = typeMap[msgText] || typeMap[rawTextOriginal.toUpperCase().trim()];
    if (type) {
      sessionData.lead_type = type;
      const emoji = { BUY:'🛒', SELL:'💰', 'SERVICE NEED':'🔧', 'SERVICE OFFER':'🛠️' }[type];
      responseMsg = `✅ Got it! You selected: *${emoji} ${type}*\n\n📝 *Describe your requirement in detail:*\n_(Minimum 10 words for best matching)_\n\n*Example:*\n_"Need 5000 plastic bottles, 500ml, food-grade PET for juice packaging in Pune"_`;
      nextStep = 'LEAD_DESC';
    } else {
      responseMsg = `⭐ *PREMIUM Lead Sharing*\n\nWhat type of requirement do you have?\n\n1️⃣ *BUY* — I need to purchase\n2️⃣ *SELL* — I have products to sell\n3️⃣ *SERVICE NEED* — I need a service\n4️⃣ *SERVICE OFFER* — I provide a service\n\n_Reply: 1, 2, 3, or 4_`;
    }
    break;
  }

  case 'LEAD_DESC': {
    const wordCount = rawTextOriginal.trim().split(/\s+/).filter(w => w.length > 0).length;
    if (wordCount >= 10) {
      sessionData.lead_description = rawTextOriginal.trim();
      responseMsg = `✅ Got it!\n\n📍 *Which city/region should we search?*\n\n*Examples:*\n• "Pune" — Single city\n• "Pune, Mumbai" — Multiple cities\n• "Maharashtra" — State-wide\n• "All India" — Pan-India\n\n_Our algorithm will prioritize vendors in your location_`;
      nextStep = 'LEAD_LOC';
    } else {
      responseMsg = `⚠️ Please provide more details *(minimum 10 words)*\n\nYou provided ${wordCount} word${wordCount === 1 ? '' : 's'}. More detail = better vendor matches.`;
    }
    break;
  }

  case 'LEAD_LOC': {
    if (rawTextOriginal.trim().length >= 2) {
      sessionData.lead_location = rawTextOriginal.trim();
      responseMsg = `✅ Got it!\n\n⏰ *How urgent is this requirement?*\n\n1️⃣ 🔴 *URGENT* — Need immediately (48 hrs)\n2️⃣ 📅 *THIS WEEK* — Within 7 days\n3️⃣ 📆 *THIS MONTH* — Within 30 days\n4️⃣ 🕐 *FLEXIBLE* — No fixed timeline\n\n_Reply 1-4_`;
      nextStep = 'LEAD_URGENCY';
    } else {
      responseMsg = `⚠️ Please enter a valid location (minimum 2 characters).`;
    }
    break;
  }

  case 'LEAD_URGENCY': {
    const urgencyMap = { '1':'URGENT', '2':'THIS WEEK', '3':'THIS MONTH', '4':'FLEXIBLE',
                         'URGENT':'URGENT', 'THIS WEEK':'THIS WEEK', 'THIS MONTH':'THIS MONTH', 'FLEXIBLE':'FLEXIBLE' };
    const urgency = urgencyMap[msgText];
    if (urgency) {
      sessionData.lead_urgency = urgency;
      responseMsg = `✅ Got it!\n\n💰 *What's your budget range?* _(Optional)_\n\n*Examples:*\n• "₹50,000 - ₹1,00,000"\n• "₹5 lakh"\n• "Negotiable"\n\n_Type SKIP to skip_`;
      nextStep = 'LEAD_BUDGET';
    } else {
      responseMsg = `⚠️ Please select urgency: 1 (URGENT), 2 (THIS WEEK), 3 (THIS MONTH), or 4 (FLEXIBLE)`;
    }
    break;
  }

  case 'LEAD_BUDGET': {
    sessionData.lead_budget = msgText === 'SKIP' ? null : rawTextOriginal.trim();
    sessionData.member_id = member.rifah_id || member.name;
    sessionData.member_name = member.business_name || member.full_name;
    sessionData.member_phone = phone;
    action = 'generate_ai_questions';
    actionData = { ...sessionData };
    responseMsg = `🤖 *AI Assistant*\n\nPerfect! Generating smart qualification questions to find your best PREMIUM match...\n\n⏳ Please wait a moment.`;
    nextStep = 'AI_Q1';
    break;
  }

  case 'AI_Q1':
  case 'AI_Q2':
  case 'AI_Q3':
  case 'AI_Q4':
  case 'AI_Q5':
  case 'AI_Q6': {
    const qNum = parseInt(currentStep.replace('AI_Q',''));
    const wordCount2 = rawTextOriginal.trim().split(/\s+/).filter(w => w.length > 0).length;
    if (wordCount2 < 1) {
      responseMsg = `⚠️ Please provide a valid answer.`;
      break;
    }
    sessionData[`ai_answer_${qNum}`] = rawTextOriginal.trim();

    const aiQuestions = sessionData.ai_questions || [];
    const totalQ = aiQuestions.length;
    const nextQNum = qNum + 1;

    if (nextQNum <= totalQ && aiQuestions[nextQNum - 1]) {
      responseMsg = `✅ Got it!\n\n*Question ${nextQNum} of ${totalQ}:*\n${aiQuestions[nextQNum - 1]}`;
      nextStep = `AI_Q${nextQNum}`;
    } else {
      // All questions answered — create premium lead + run matching
      action = 'create_premium_lead';
      actionData = { ...sessionData };
      responseMsg = `✅ *All details captured!*\n\n⭐ *PREMIUM Processing:*\n🔍 Searching 1 lakh+ businesses...\n📊 Running smart matching algorithm...\n\n_Results in 5-10 seconds_`;
      nextStep = 'VENDOR_SELECTION';
    }
    break;
  }

  case 'VENDOR_SELECTION': {
    const matchedVendors = sessionData.matched_vendors || [];

    // If no vendors yet — matching is still running or zero results
    if (!matchedVendors.length) {
      responseMsg = `🔍 Still searching for matches... Please wait a moment and try again.`;
      break;
    }

    // Parse selection: "1,2,3" or "1-5" or "ALL"
    let selectedIndices = [];
    const upperMsg2 = rawTextOriginal.trim().toUpperCase();

    if (upperMsg2 === 'ALL') {
      selectedIndices = matchedVendors.map((_, i) => i);
    } else {
      const parts = upperMsg2.split(',');
      for (const part of parts) {
        const trimmed = part.trim();
        const rangeParts = trimmed.split('-');
        if (rangeParts.length === 2 && !isNaN(rangeParts[0]) && !isNaN(rangeParts[1])) {
          const start = parseInt(rangeParts[0]) - 1;
          const end = parseInt(rangeParts[1]) - 1;
          const lo = Math.min(start, end);
          const hi = Math.max(start, end);
          for (let i = lo; i <= hi && i < matchedVendors.length; i++) {
            if (i >= 0) selectedIndices.push(i);
          }
        } else {
          const idx = parseInt(trimmed) - 1;
          if (!isNaN(idx) && idx >= 0 && idx < matchedVendors.length) {
            selectedIndices.push(idx);
          }
        }
      }
      selectedIndices = [...new Set(selectedIndices)]; // deduplicate
    }

    if (!selectedIndices.length) {
      responseMsg = `❌ Invalid selection. Please reply with:\n• Numbers: "1,2,3"\n• Range: "1-5"\n• All: "ALL"\n\nAvailable: 1 to ${matchedVendors.length}`;
      break;
    }

    const selectedVendors = selectedIndices.map(i => matchedVendors[i]);
    sessionData.selected_vendors = selectedVendors;

    const confirmList = selectedVendors.map((v, i) =>
      `${i+1}. ${v.business_name}, ${v.city_state} (Match: ${v.match_score}/100)`
    ).join('\n');

    responseMsg = `✅ You selected *${selectedVendors.length} vendor(s)*:\n\n${confirmList}\n\nProceed? Reply:\n*YES* — Send personalized introductions\n*CHANGE* — Re-select vendors`;
    nextStep = 'VENDOR_CONFIRM';
    break;
  }

  case 'VENDOR_CONFIRM': {
    if (msgText === 'CHANGE') {
      const matchedVendors = sessionData.matched_vendors || [];
      const listMsg = matchedVendors.map((v, i) =>
        `${i+1}. *${v.business_name}*, ${v.city_state}\n   Score: ${v.match_score}/100 | ${v.industry}`
      ).join('\n');
      responseMsg = `📋 *Matched Vendors:*\n\n${listMsg}\n\nReply with numbers (e.g. "1,2,3"), a range (e.g. "1-5"), or "ALL":`;
      nextStep = 'VENDOR_SELECTION';
    } else if (msgText === 'YES') {
      action = 'send_introductions';
      actionData = { selected_vendors: sessionData.selected_vendors || [], lead_id: sessionData.premium_lead_id, phone };
      responseMsg = `⭐ *Sending PREMIUM introductions...*\n\nEach vendor receives a personalized message with your requirements.\nYou'll be notified when vendors respond.\n\n_Introductions being sent now..._`;
      nextStep = 'COMPLETED_BUYER';
    } else {
      responseMsg = `Please reply *YES* to send introductions or *CHANGE* to re-select vendors.`;
    }
    break;
  }

  case 'VENDOR_INTRO': {
    if (msgText === 'INTERESTED' || msgText === 'YES') {
      if (!member) {
        responseMsg = `⚠️ You need to be a registered RIFAH member to respond to leads.\n\nPlease send *Hi* to register.`;
        nextStep = 'IDLE';
      } else {
        action = 'generate_vendor_questions';
        actionData = { ...sessionData, vendor_id: member.rifah_id || member.name, vendor_name: member.business_name || member.full_name, vendor_phone: phone };
        sessionData.vendor_id = member.rifah_id || member.name;
        sessionData.vendor_name = member.business_name || member.full_name;
        responseMsg = `🤖 *Vendor Qualification*\n\nGreat! I'll ask 6 quick questions to match you with this PREMIUM lead.\n\n⏳ Preparing questions...`;
        nextStep = 'VENDOR_Q1';
      }
    } else if (msgText === 'DETAILS') {
      const leadInfo = sessionData.lead_for_vendor || {};
      responseMsg = `📋 *Complete Lead Details:*\n\n📝 ${leadInfo.description || 'No description available'}\n📍 Location: ${leadInfo.location || 'N/A'}\n💰 Budget: ${leadInfo.budget || 'Negotiable'}\n⏱️ Urgency: ${leadInfo.urgency || 'N/A'}\n👤 Posted by: PREMIUM member\n\nInterested? Reply *INTERESTED* or *NOT NOW*`;
    } else if (msgText === 'NOT NOW' || msgText === 'NO') {
      sessionData.intro_status = 'Declined';
      action = 'vendor_declined';
      actionData = { lead_id: sessionData.lead_id, vendor_id: member?.rifah_id || '', vendor_phone: phone };
      responseMsg = `No problem! We appreciate your time. We'll keep you in mind for future PREMIUM leads. 👋`;
      nextStep = 'IDLE';
    } else {
      responseMsg = `👋 *PREMIUM Lead Opportunity*\n\nReply:\n*INTERESTED* — Proceed with qualification\n*DETAILS* — See complete requirements\n*NOT NOW* — Decline this lead`;
    }
    break;
  }

  case 'VENDOR_Q1':
  case 'VENDOR_Q2':
  case 'VENDOR_Q3':
  case 'VENDOR_Q4':
  case 'VENDOR_Q5':
  case 'VENDOR_Q6': {
    const vqNum = parseInt(currentStep.replace('VENDOR_Q',''));
    sessionData[`vendor_answer_${vqNum}`] = rawTextOriginal.trim();

    const vendorQs = sessionData.vendor_questions || [];
    const totalVQ = Math.min(vendorQs.length, 6);
    const nextVQ = vqNum + 1;

    if (nextVQ <= totalVQ) {
      const qObj = vendorQs[nextVQ - 1];
      const qText = typeof qObj === 'object' ? qObj.q : qObj;
      responseMsg = `✅ Got it!\n\n*Question ${nextVQ} of ${totalVQ}:*\n${qText}\n\n_Please provide your answer:_`;
      nextStep = `VENDOR_Q${nextVQ}`;
    } else {
      action = 'calculate_vendor_score';
      actionData = { ...sessionData };
      responseMsg = `✅ *All questions answered!*\n\nCalculating your compatibility score for this PREMIUM lead... 📊`;
      nextStep = 'VENDOR_SCORE';
    }
    break;
  }

  case 'VENDOR_SCORE': {
    if (msgText === 'SUBMIT') {
      action = 'submit_vendor_interest';
      actionData = { ...sessionData };
      responseMsg = `⏳ Submitting your PREMIUM interest...`;
      nextStep = 'VENDOR_SUBMIT';
    } else if (msgText === 'CANCEL') {
      responseMsg = `Understood. We'll notify you about future matching leads.`;
      nextStep = 'IDLE';
    } else {
      const score = sessionData.compatibility_score || 0;
      const emoji = score >= 80 ? '🌟🌟🌟' : score >= 70 ? '🌟🌟' : score >= 50 ? '🌟' : '⚠️';
      responseMsg = `📊 *PREMIUM Match Score*\n\nCompatibility: *${score}/100* ${emoji}\n\n${score >= 70 ? '🌟 Excellent match! High chance of connection.' : score >= 50 ? '✅ Good fit. Strong candidate.' : '⚠️ Moderate match.'}\n\nReply *SUBMIT* to express interest (admin reviews within 2 hours)\nReply *CANCEL* to skip`;
    }
    break;
  }

  case 'VENDOR_SUBMIT': {
    responseMsg = `⏳ Processing your PREMIUM submission...`;
    break;
  }

  default: {
    return [{ json: { skip: true, phone, currentStep } }];
  }
}

return [{
  json: {
    phone,
    responseMsg,
    nextStep,
    action,
    actionData: JSON.stringify(actionData),
    sessionData: JSON.stringify(sessionData),
    sessionName,
    currentStep,
    shouldSendMsg: responseMsg.length > 0,
    skip: false
  }
}];

const sm = $input.first().json;
const sessionName = sm.sessionName;
const phone = sm.phone;
const nextStep = sm.nextStep;
const sessionData = sm.sessionData;

const isUpdate = !!sessionName;
const method = isUpdate ? 'PUT' : 'POST';
const urlSuffix = isUpdate ? `/${encodeURIComponent(sessionName)}` : '';

return [{ json: { method, urlSuffix, phone, nextStep, sessionData, isUpdate } }];

const sm = $('State Machine Premium').first().json;
const ad = JSON.parse(sm.actionData || '{}');
const ts = new Date().toISOString().replace('T',' ').substring(0,19);
const phone = sm.phone;

const leadType = ad.lead_type || ad.lead_type || 'BUY';
const desc = ad.lead_description || '';
const loc = ad.lead_location || '';
const urgency = ad.lead_urgency || 'FLEXIBLE';
const budget = ad.lead_budget || null;
const memberId = ad.member_id || '';
const memberName = ad.member_name || '';

// Collect AI answers
const aiAnswers = {};
for (let i = 1; i <= 6; i++) {
  if (ad[`ai_answer_${i}`]) aiAnswers[`Q${i}`] = ad[`ai_answer_${i}`];
}

const leadId = `LEAD-PREM-${new Date().getFullYear()}-${Date.now().toString().slice(-6)}`;
const title = `${leadType}: ${desc.substring(0,60)}${desc.length > 60 ? '...' : ''}`;

return [{ json: {
  lead_id: leadId,
  member_id: memberId,
  member_name: memberName,
  member_phone: phone,
  tier: 'PREMIUM',
  lead_type: leadType,
  title,
  description: desc,
  location: loc,
  urgency,
  budget,
  ai_qualification: JSON.stringify(aiAnswers),
  status: 'Awaiting User Response',
  created_at: ts,
  posted_to_groups: '0',
  is_premium_request: 0,
  matched_vendors: '[]',
  introduction_sent: '[]',
  interested_vendors: '[]',
  phone,
  sd: sm.sessionData
} }];

const leadData = $('Build Premium Lead Data').first().json;
const vendorsRaw = $input.first().json?.data || [];
const leadLocation = (leadData.location || '').toLowerCase();
const leadIndustry = (leadData.lead_type || '').toLowerCase();
const leadDesc = (leadData.description || '').toLowerCase();

// Industry keyword map for related matching
const industryKeywords = {
  'packaging': ['bottle','container','packaging','box','carton','pouch','wrap'],
  'manufacturing': ['machine','equipment','manufacturing','production','fabricat'],
  'food': ['food','beverage','juice','snack','ingredient','grain','spice'],
  'textile': ['fabric','cloth','textile','garment','cotton','yarn','knit'],
  'it': ['software','website','app','development','digital','tech','cloud'],
  'construction': ['construction','building','cement','steel','plumb','electr'],
  'retail': ['retail','shop','store','outlet','wholesale','distribution'],
  'trading': ['trading','export','import','wholesale','supply','procurement']
};

const relatedIndustries = {
  'packaging': ['manufacturing','food','retail'],
  'food': ['packaging','retail','trading'],
  'textile': ['manufacturing','retail','trading'],
  'it': ['services'],
  'construction': ['manufacturing','trading'],
  'retail': ['trading','packaging'],
  'trading': ['manufacturing','retail','packaging']
};

function getIndustryFromDesc(desc) {
  for (const [ind, kws] of Object.entries(industryKeywords)) {
    if (kws.some(k => desc.includes(k))) return ind;
  }
  return '';
}

const detectedLeadIndustry = getIndustryFromDesc(leadDesc);
const cityKeyword = leadLocation.split(',')[0].trim();

const scored = vendorsRaw.map(v => {
  let score = 0;
  const vCity = (v.city_state || '').toLowerCase();
  const vInd = (v.industry || '').toLowerCase();
  const vTier = (v.membership_tier || '').toLowerCase();

  // City match
  if (vCity.includes(cityKeyword) || cityKeyword.includes(vCity.split(',')[0].trim())) score += 30;

  // Industry match
  if (detectedLeadIndustry && vInd.includes(detectedLeadIndustry)) {
    score += 20;
  } else if (detectedLeadIndustry) {
    const related = relatedIndustries[detectedLeadIndustry] || [];
    if (related.some(r => vInd.includes(r))) score += 10;
  }

  // Premium member bonus
  if (vTier === 'premium') score += 5;

  // Experience proxy (use rifah_id year if available)
  const idYear = parseInt((v.rifah_id || '').replace(/\D/g,'').substring(0,4));
  if (!isNaN(idYear)) {
    const exp = Math.max(0, new Date().getFullYear() - idYear);
    score += Math.min(exp, 10);
  }

  return {
    vendor_id: v.rifah_id || v.name,
    business_name: v.business_name || v.full_name || 'Unknown',
    city_state: v.city_state || '',
    industry: v.industry || '',
    tier: v.membership_tier || 'FREE',
    phone: v.whatsapp_number || '',
    match_score: score
  };
}).filter(v => v.match_score >= 40)
  .sort((a,b) => b.match_score - a.match_score)
  .slice(0, 10);

return [{ json: { matched: scored, lead_id: leadData.lead_id, phone: leadData.phone, sd: leadData.sd } }];

const matchData = $('Run Matching Algorithm').first().json;
const matched = matchData.matched || [];
const phone = matchData.phone;
const leadId = matchData.lead_id;

let sd = {};
try { sd = JSON.parse(matchData.sd || '{}'); } catch(e) {}

// Update session data with matched vendors + lead ID
sd.matched_vendors = matched;
sd.premium_lead_id = leadId;

const isFewMatches = matched.length < 3;

let listMsg = '';
if (matched.length > 0) {
  const vendorLines = matched.map((v, i) =>
    `${i+1}. *${v.business_name}*, ${v.city_state}\n   Score: ${v.match_score}/100 | ${v.industry} | ${v.tier}`
  ).join('\n');
  listMsg = `⭐ *PREMIUM Smart Match Results*\n\nFound *${matched.length} vendor(s)* matching your requirement:\n\n${vendorLines}\n\n${isFewMatches ? '_(Also posting to premium groups as fallback)_\n\n' : ''}Reply with vendor numbers to contact directly:\n• Single: "1" or "1,2,3"\n• Range: "1-5"\n• All: "ALL"`;
} else {
  listMsg = `🔍 *No direct matches found*\n\nNo vendors in our database perfectly match your requirement right now.\n\n⭐ *Posting to 5-7 PREMIUM WhatsApp groups now...*\nVendors will see your ⭐ PREMIUM REQUEST and respond directly.\n\nYou'll be notified when vendors respond.`;
}

return [{ json: { phone, listMsg, sd: JSON.stringify(sd), leadId, isFewMatches, matchCount: matched.length } }];

const res = $input.first().json;
const content = res?.choices?.[0]?.message?.content || '';
const ad = JSON.parse($('State Machine Premium').first().json.actionData || '{}');
